package org.eclipse.rdf4j.sail.lmdb.sketch.omni;

import java.lang.foreign.MemorySegment;
import java.util.Objects;

/** Immutable compact OmniSketch. */
public abstract class CompactOmniSketch extends OmniSketch {
	CompactOmniSketch() {
	}

	/** Heapifies a compact OmniSketch from a serialized byte array. */
	public static CompactOmniSketch heapify(final byte[] byteArray) {
		Objects.requireNonNull(byteArray, "Source byte array must not be null");
		return heapify(MemorySegment.ofArray(byteArray));
	}

	/** Heapifies a compact OmniSketch from a serialized MemorySegment image. */
	public static CompactOmniSketch heapify(final MemorySegment srcSeg) {
		return OmniSketchSerializationUtil.heapify(srcSeg);
	}

	/** Wraps a compact OmniSketch MemorySegment image for read-only access without copying all cells. */
	public static CompactOmniSketch wrap(final MemorySegment srcSeg) {
		return OmniSketchSerializationUtil.wrap(srcSeg);
	}

	@Override
	public final boolean isCompact() {
		return true;
	}

	@Override
	public final CompactOmniSketch compact() {
		return this;
	}

	@Override
	public final int getCurrentBytes() {
		return getCompactBytes();
	}
}
